// R2-CORS: Detectar preflight OPTIONS por cabecera estándar.
// Los preflights SIEMPRE incluyen Access-Control-Request-Method.
// Los POST normales nunca lo incluyen.
const wb = $json || {};
const headers = wb.headers || {};
const acrm = headers['access-control-request-method']
           || headers['Access-Control-Request-Method']
           || '';
const isOptions = acrm.trim() !== '';
return [{ json: { ...wb, _isOptions: isOptions } }];

const body = $json.body || $json || {};
const raw = body.entregable_version_id;
const modo = String(body.modo || 'QA').trim() || 'QA';

let ok = true;
let error = '';
let id = null;

if (raw === undefined || raw === null || String(raw).trim() === '') {
  ok = false;
  error = 'entregable_version_id_requerido';
} else if (!/^\d+$/.test(String(raw).trim())) {
  ok = false;
  error = 'entregable_version_id_invalido';
} else {
  id = Number(String(raw).trim());
  if (!Number.isSafeInteger(id) || id <= 0) {
    ok = false;
    error = 'entregable_version_id_invalido';
    id = null;
  }
}

return [{
  json: {
    ok_input: ok,
    error_input: error,
    entregable_version_id: id,
    entregable_version_id_sql: ok ? String(id) : '-1',
    modo
  }
}];

const validacion = $('Code - Validar Input Consulta').first().json || {};
const row = $json || {};
const data = row.data && typeof row.data === 'object' ? row.data : null;

function esc(value) {
  return String(value == null ? '' : value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}
function asArray(value) {
  if (Array.isArray(value)) return value;
  if (value == null || value === '') return [];
  return [value];
}
function text(value) {
  if (value == null) return '';
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  return JSON.stringify(value);
}
function list(items) {
  const arr = asArray(items).map(x => `<li>${esc(text(x))}</li>`).join('');
  return arr ? `<ul>${arr}</ul>` : '<p class="muted">Sin datos registrados.</p>';
}
function section(title, body) {
  return `<section><h2>${esc(title)}</h2>${body}</section>`;
}
function compactJsonBlock(obj) {
  if (!obj || typeof obj !== 'object') return '<p class="muted">Sin datos registrados.</p>';
  const entries = Object.entries(obj).slice(0, 8).map(([k, v]) => `<dt>${esc(k)}</dt><dd>${esc(text(v)).slice(0, 600)}</dd>`).join('');
  return entries ? `<dl>${entries}</dl>` : '<p class="muted">Sin datos registrados.</p>';
}

if (validacion.ok_input !== true) {
  return [{ json: {
    ok: false,
    error: validacion.error_input || 'entregable_version_id_invalido',
    entregable_version_id: validacion.entregable_version_id || null,
    mensaje: validacion.error_input === 'entregable_version_id_requerido'
      ? 'Debe enviar entregable_version_id.'
      : 'entregable_version_id debe ser numerico.'
  } }];
}

if (!data) {
  return [{ json: {
    ok: false,
    error: 'entregable_no_encontrado',
    entregable_version_id: validacion.entregable_version_id,
    mensaje: 'No existe una version de entregable con el ID solicitado.'
  } }];
}

const objeto = data.objeto_estandar_json || {};
const ficha = data.ficha_analitica_json || {};
const revision = data.revision_qa_json || {};
const cargo = objeto.cargo || {};
const tituloCargo = cargo.nombre || ficha.cargo || ficha.nombre_cargo || objeto.cargo_nombre || 'Entregable RRHH';
const alertas = asArray(objeto.alertas_vacios).concat(asArray(revision.alertas));

const html = `<!doctype html>
<html lang="es">
<head>
<meta charset="utf-8">
<title>${esc(tituloCargo)} - ${esc(data.codigo_expediente)}</title>
<style>
  body { font-family: Arial, sans-serif; color: #1f2933; line-height: 1.45; margin: 24px; }
  header { border-bottom: 2px solid #d9e2ec; margin-bottom: 18px; padding-bottom: 12px; }
  h1 { font-size: 24px; margin: 0 0 6px; }
  h2 { font-size: 17px; border-bottom: 1px solid #e4e7eb; padding-bottom: 4px; margin-top: 20px; }
  .meta { color: #52606d; font-size: 13px; }
  .badge { display: inline-block; padding: 3px 8px; border-radius: 4px; background: #e0f2fe; color: #075985; font-size: 12px; margin-right: 6px; }
  .muted { color: #7b8794; }
  ul { margin-top: 6px; }
  dl { display: grid; grid-template-columns: 180px 1fr; gap: 6px 12px; }
  dt { font-weight: bold; color: #334e68; }
  dd { margin: 0; }
  section { break-inside: avoid; }
</style>
</head>
<body>
<header>
  <h1>${esc(tituloCargo)}</h1>
  <div class="meta">
    <span class="badge">${esc(data.version || '')}</span>
    <span class="badge">${esc(data.estado_qa_resumido || '')}</span>
    Expediente: ${esc(data.codigo_expediente || '')} | Version ID: ${esc(data.entregable_version_id || '')}
  </div>
</header>
${section('Proposito', `<p>${esc(objeto.proposito || ficha.proposito || 'Sin proposito registrado.')}</p>`)}
${section('Funciones clave', list(objeto.funciones_clave))}
${section('Responsabilidades', list(objeto.responsabilidades))}
${section('Alertas y vacios', list(alertas))}
${section('Observaciones QA', `<p>${esc(objeto.observaciones_qa || revision.resumen || revision.observaciones || 'Sin observaciones QA registradas.')}</p>`)}
${section('Ficha analitica resumida', compactJsonBlock(ficha))}
${section('Revision QA resumida', compactJsonBlock(revision))}
</body>
</html>`;

return [{ json: {
  ok: true,
  entregable_version_id: data.entregable_version_id,
  entregable_id: data.entregable_id,
  codigo_expediente: data.codigo_expediente,
  estado_expediente: data.estado_expediente,
  pregunta_actual_id: data.pregunta_actual_id,
  progreso_pct: data.progreso_pct,
  version: data.version,
  version_generador: data.version_generador,
  fecha_generacion: data.fecha_generacion,
  estado_qa_resumido: data.estado_qa_resumido,
  calidad_general: data.calidad_general,
  apto_para_entrega: data.apto_para_entrega,
  requiere_revision_humana: data.requiere_revision_humana,
  nivel_revision_humana: data.nivel_revision_humana,
  parse_errors: data.parse_errors || [],
  objeto_estandar: objeto,
  ficha_analitica: ficha,
  revision_qa: revision,
  html_preview: html
} }];
